<template lang="en">
<div>
    <!-- RevenueComparisonReport -->
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <Unauthorized controller="InvoiceReport" action="RevenueComparisonReport">
            <div ref="hellp" id="divMaindealData">
                <div class="border p-3">
                    <Form ref="JobPostForm">
                        <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'></dynamic-form>
                        <div class="row placeholder">
                            <div class="col-md-12 p-0">
                                <ReportViewer v-if="parameter.length > 0" :key="loadKey" :viewerId="'viewer_' + loadKey" :parameter="parameter" :reportPath="reportPath">
                                </ReportViewer>
                            </div>
                        </div>
                    </Form>
                </div>
            </div>
        </Unauthorized>
    </section>
</div>
</template>

<script>
import Unauthorized from "@/components/Common/Unauthorized.vue";
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import moment from 'moment';
import { locateBillingService } from "../../services/locateBillingService";
export default {
    components: {
        ReportViewer,
        Unauthorized
    },
    data() {
        return {
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            isLoading: false,
            reportPath: null,
            parameter: [],
            DataLoaded: 0,
            isSupervisor:false,
            loadKey: 0,
            currentReportParams: null,
            selectedClientId: [],
            FormSchema: [{
                    layoutType: "triple",
                    Data: [{
                            astype: "SearchableSelectField",
                            label: this.$t('CONTRACTNAME'),
                            name: "ContractName",
                            value: "",
                            placeholder: this.$t('SelectClient'),
                            visibility: true,
                            isSearch: true,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    active: true,
                                    inactive: true,
                                    clear: true
                                },
                                itemFields: ['text', 'status'],
                                isMultiple: false,
                                groupFields: ['groupText'],
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                                onChange: this.onSelectionChange
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('Invoice Grouping'),
                            name: "InvoiceGrouping",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Invoice Grouping'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                },
                                groupFields: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("Invoice Status"),
                            name: "InvoiceStatus",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Invoice Status'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: false,
                  
                                groupFields: [],
                                minSearchLength: 0,
                                actionButtons: {
                                    clear: true
                                },
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                }
                            },
                            validationRules: {
                                required: false
                            }
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [{
                        astype: "DateRangeField",
                        label: this.$t('Invoice Date'),
                        name: "InvoiceDateFrom",
                        value: "",
                        placeholder: "",
                        config: {
                            format: "MM/DD/YYYY",
                            maxDate: false,
                            onChange: this.setTimerDate,
                            datePickerConfig: {
                                useCurrent: true,
                                showClear: true,
                                showClose: true,
                                allowInputToggle: false,
                                minDate: true,
                                maxDate: true,
                                widgetPositioning: {
                                    horizontal: 'right',
                                    vertical: 'bottom'
                                }
                            },
                            secondDatePickerConfig: {
                                useCurrent: false,
                                showClear: true,
                                showClose: true,
                                allowInputToggle: false,
                                minDate: true,
                                maxDate: true,
                                widgetPositioning: {
                                    horizontal: 'right',
                                    vertical: 'bottom'
                                }
                            },
                        },
                        validationRules: {
                            "required": true
                        },
                    },
                 {
                    astype: "SearchableSelectField",
                    label: this.$t('Biller'),
                    name: "Biller",
                    value: "",
                    placeholder: this.$t('Select') + " " + this.$t('Biller'),
                    visibility: false,
                    isSearch: true,
                    config: {
                        options: [],
                        actionButtons: {
                            selectAll: true,
                            active: false,
                            inactive: false,
                            clear: true
                        },
                        itemFields: ['text', 'status'],
                        isMultiple: true,
                        groupFields: [],
                        minSearchLength: 0,
                        statusFieldConfig: {
                            fieldName: 'status',
                            activeValues: ['Active', 'active'],
                            inactiveValues: ['Inactive', 'inactive'],
                            activeColor: '#28a745',
                            inactiveColor: '#dc3545'
                        }
                    },
                    validationRules: {
                        "required": false
                    },
                }]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        }
    },
    mounted() {
        window.handleExceededLink = () => {
            this.saveReportRequest();
        };
    },
    beforeDestroy() {
        delete window.handleExceededLink;
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.fetchclientlist();
        await vm.GetCommonStatusCodes();
        await vm.GetBillerList();
        await vm.BindSupervisor();
        await vm.GetEmailConfigurationSetting();
    },
    methods: {
        setTimerDate: function (selectedDate, field, isSecondPicker = false) {
            const vm = this;

            const rangeFieldName = field.name; // e.g. "AuditStartFrom"

            // Always get latest values (important!)
            let startVal = vm.$refs.BarcodeReport?.getPropertyValue(rangeFieldName, "value") || null;
            let endVal = vm.$refs.BarcodeReport?.getPropertyValue(rangeFieldName, "secondValue") || null;

            const toMoment = (val) => val ? moment(val, "MM/DD/YYYY", true) : null;

            let start = toMoment(startVal);
            let end = toMoment(endVal);
            const today = moment().startOf('day');

            // ────────────────────────────────────────────────
            // Always enforce constraints based on CURRENT values
            // (even if the change was invalid/ignored by picker)
            // ────────────────────────────────────────────────

            // Update minDate for End picker (based on current Start)
            if (start?.isValid()) {
                vm.$refs.BarcodeReport.updateProperty(
                    rangeFieldName,
                    "config.secondDatePickerConfig.minDate",
                    start.format("MM/DD/YYYY")
                );
            } else {
                // If Start cleared → remove min restriction on End
                vm.$refs.BarcodeReport.updateProperty(
                    rangeFieldName,
                    "config.secondDatePickerConfig.minDate",
                    false
                );
            }

            // Update maxDate for Start picker (based on current End)
            if (end?.isValid()) {
                vm.$refs.BarcodeReport.updateProperty(
                    rangeFieldName,
                    "config.datePickerConfig.maxDate",
                    end.format("MM/DD/YYYY")
                );
            } else {
                // If End cleared → remove max restriction on Start
                vm.$refs.BarcodeReport.updateProperty(
                    rangeFieldName,
                    "config.datePickerConfig.maxDate",
                    false
                );
            }

            // ────────────────────────────────────────────────
            // Auto-adjust logic (only if change was accepted)
            // ────────────────────────────────────────────────

            if (!isSecondPicker) { // Start changed
                if (start?.isValid()) {
                    // If End empty → set to TODAY
                    if (!end?.isValid()) {
                        const newEnd = today.format("MM/DD/YYYY");
                        vm.$refs.BarcodeReport.updateProperty(rangeFieldName, "secondValue", newEnd);
                    }
                    // If End < Start → adjust End to Start
                    else if (end.isBefore(start)) {
                        const newEnd = start.format("MM/DD/YYYY");
                        vm.$refs.BarcodeReport.updateProperty(rangeFieldName, "secondValue", newEnd);
                    }
                }
            }

            if (isSecondPicker) { // End changed
                if (end?.isValid()) {
                    // If Start empty → set to End (or today if future)
                    if (!start?.isValid()) {
                        const newStart = end.isAfter(today) ? today.format("MM/DD/YYYY") : end.format("MM/DD/YYYY");
                        vm.$refs.BarcodeReport.updateProperty(rangeFieldName, "value", newStart);
                    }
                    // If Start > End → adjust Start to End
                    else if (start.isAfter(end)) {
                        const newStart = end.format("MM/DD/YYYY");
                        vm.$refs.BarcodeReport.updateProperty(rangeFieldName, "value", newStart);
                    }
                }
            }

            // Final refresh (very important)
            vm.$refs.BarcodeReport?.UpdateKeyValue();
        },
        formatDate(value) {
            if (!value) return null;
            const m = moment(value);
            return m.isValid() ? m.format('MM-DD-YYYY') : null;
        },
         GetBillerList: async function () {
            var vm = this;
            var params = `reqFrom=all&moduleName=Billing`;
            await locateBillingService.GetBillerList(params).then((response) => {
                let SelectedBillerList = [];
                var BillerList = JSON.parse(response.data.result);
                if (BillerList != null) {
                    BillerList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.USERNAME,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.USERNAME,
                            value: item.USERID
                        };
                        SelectedBillerList.push(obj);
                    });
                    vm.$refs.BarcodeReport.updateProperty("Biller", "config.options", SelectedBillerList);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        async onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];

            vm.InvoiceDateFrom = vm.$refs.BarcodeReport.getPropertyValue("InvoiceDateFrom", "value");
            vm.InvoiceDateTo = vm.$refs.BarcodeReport.getPropertyValue("InvoiceDateFrom", "secondValue");

            let myObj = {
                reportName: "revenuecomparisonreport",
                ClientIds: e.ContractName,
                DivisionId: e.InvoiceGrouping.length > 0 ? e.InvoiceGrouping.join(",") : '',   
                StatusIds: e.InvoiceStatus,
                DueDateFrom: vm.formatDate(vm.InvoiceDateFrom),
                DueDateTo: vm.formatDate(vm.InvoiceDateTo),
                BillerIds: e.Biller && e.Biller.length > 0 ? e.Biller.join(",") : ''  
            };
            vm.currentReportParams = myObj;
            var postString = JSON.stringify(myObj);
            await DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
                vm.isLoading = false;
            }).catch(function (error) {
                console.error("Error loading report:", error);
                vm.isLoading = false;
            });
        },
        ClearAll: function () {
            var vm = this;
            vm.FormSchema[0].Data[1].config.options = [];
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[1].Data[0].value = '';
            (vm.FormSchema)[1].Data[0].secondValue = '';
            (vm.FormSchema)[1].Data[1].value = '';

            vm.reportPath = '';
            vm.parameter = [];
            vm.currentReportParams = null;
            vm.$refs.BarcodeReport.validateForm.reset();
        },
         BindSupervisor: async function () {
            var vm = this;           
            await locateBillingService.CheckIsSupervisor().then(response => {
                if (response.data) {                      
                    vm.isSupervisor=response.data;
                }
            });
        },
        async GetEmailConfigurationSetting() {
            var vm = this;
            var params = `companyId=${vm.companyId}&userId=${vm.userId}&moduleName=User&configkey=CanViewAllContractData`;
            await locateBillingService.GetEmailConfigurationSetting(params).then(response => {
                debugger
                const value = response.data?.[0]?.CONFIG_DATA_VALUE;                
                vm.canViewAllContractData = value && value.toLowerCase() === 'yes';
                vm.canViewAllContractDataString = value;
                vm.hasAccess = (
                    vm.isSupervisor === true ||
                    vm.GetUserInfo?.UserType === "CA" ||
                    vm.canViewAllContractData === true ||
                    (vm.canViewAllContractDataString &&
                        vm.canViewAllContractDataString.toLowerCase() === "yes")
                );
                if (vm.GetUserInfo?.UserType === "CA") {
                    (vm.FormSchema)[1].Data[1].visibility = true;   
                } else {
                    (vm.FormSchema)[1].Data[1].visibility = false;  
                }              
             })
            .catch(err => {
                console.error("GetEmailConfigurationSetting error:", err);
            });
        },
        fetchclientlist: async function () {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOMREPORT`;
            await locateBillingService.getClientList(url).then(response => {
                vm.isLoading = false;
                vm.ClientData = response.data.items;
                vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", vm.ClientData);
                vm.$refs.BarcodeReport.UpdateKeyValue();

            }).catch(error => {
                vm.isLoading = false;
                vm.ClientData = [];
                vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", vm.ClientData);
                vm.$refs.BarcodeReport.UpdateKeyValue();
                console.error('Error fetching client list:', error);
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        onSelectionChange(value, x) {
            var vm = this;
            vm.isLoading = true;
            if (x && x.length > 0) {
                vm.selectedClientId = x;
                vm.clientId = x;
            } else {
                vm.selectedClientId = null;
                vm.clientId = null;
                vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "config.options", []);
                vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "value", '');
            }
            var url = `clientId=${vm.selectedClientId}&configId=&reqFrom=&clientIds=`;
            DataServices.GetInvoiceGrouping(url).then(response => {
                let SelectedUtilityList = [];
                vm.isLoading = false;
                var UtilityList = response.data;
                if (UtilityList != null) {
                    UtilityList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.NOTE,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.NOTE,
                            value: item.ID
                        };
                        SelectedUtilityList.push(obj);
                    });
                    vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "config.options", SelectedUtilityList);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            }).catch(error => {
                vm.isLoading = false;
                vm.UtilityList = [];
                vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "config.options", []);
                vm.$refs.BarcodeReport.updateProperty("InvoiceGrouping", "value", '');
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        GetCommonStatusCodes: async function () {
            var vm = this;
            vm.isLoading = true;
            var url = `statusTypeName=ClientBilling`;
            await DataServices.GetCommonStatusCodes(url).then((response) => {
                let SelectedStateList = [];
                vm.isLoading = false;
                if (response.data.length > 0) {
                    var StatusData = response.data;
                    StatusData.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.STATUS_NAME,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.STATUS_NAME,
                            value: item.STATUS_ID
                        };
                        SelectedStateList.push(obj);
                    });
                    vm.$refs.BarcodeReport.updateProperty("InvoiceStatus", "config.options", SelectedStateList);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        async saveReportRequest() {
            var vm = this;
            vm.isLoading = true;
            try {
                if (!vm.currentReportParams) {
                    console.error('No report parameters available. Please generate a report first.');
                    return;
                }

                const params = {
                    reportName: vm.currentReportParams.reportName || 'revenuecomparisonreport',
                    hdnClientId: vm.currentReportParams.ClientIds || '',
                    startDate: vm.currentReportParams.dateFrom || '',
                    endDate: vm.currentReportParams.dateTo || '',
                    DivisionInvoiceFrequency: vm.currentReportParams.Frequency || '',
                    hdnStatusId: vm.currentReportParams.Status || '',
                    hdnState: vm.currentReportParams.State || '',
                    UtilityNames: vm.currentReportParams.UtilityName || '',
                    DivisionNames: vm.currentReportParams.Invoicegrouping || '',
                    ProcessFromDate: vm.currentReportParams.ProccessFromDate || '',
                    ProcessToDate: vm.currentReportParams.ProccessToDate || '',
                    Workcode: vm.currentReportParams.Workcode || '',
                    BillerIds: vm.currentReportParams.BillerIds || ''   
                };

                console.log('Saving report request with params:', params);

                let response = await DataServices.SaveReportRequest(params);
                if (response.data && response.data.result === 'success') {
                    vm.ShowAlert("Request submitted successfully", "success", true, vm.$t("Alert"));
                } else {
                    vm.ShowAlert("We couldn't submit your request. Please try again.", "failure", true, vm.$t("Alert"));
                }
            } catch (error) {
                console.error('Error saving report request:', error);
            } finally {
                vm.isLoading = false;
            }
        }
    }
};
</script>